// ??? BIKE LOGISTICS PROMPT ????????????????????????????????????????????????????

function buildLogisticsPrompt(destinations, a) {

  const destList = destinations.map(d => {

    const meta = LOCATION_META[d.name] || {};

    const curated = CURATED_HOTELS[d.name];

    const lat = curated?.[0]?.lat;

    const lng = curated?.[0]?.lng;

    const gps = (lat && lng) ? ` (route-start GPS: ${lat.toFixed(4)},${lng.toFixed(4)})` : "";

    const zone = meta.stayZone ? ` | Stay zone: ${meta.stayZone}` : "";

    return `${d.name}${zone}${gps}`;

  }).join("\n  ");

  return [

    "You are a cycling travel researcher. Use web search to find real hotels for cyclists at these specific stay zones:\n  "+destList+".",

    "",

    "CRITICAL: You MUST return 3 hotels per destination. Do not return fewer.",

    "Hotels MUST be in the STAY ZONE listed — within 2km of the cycling route start.",

    "Do NOT suggest hotels in the city centre if the stay zone specifies a different area.",

    "ONLY use Booking.com, Hotels.com or LastMinute.com as sources.",

    "For each hotel include:",

    "- Exact hotel name as it appears on the booking site",

    "- Star rating (1-5 stars)",

    "- Guest score out of 10 (e.g. 8.6/10) from the booking site",

    "- Number of reviews",

    "- Approximate price per night in local currency",

    "- Direct URL to that hotel on booking.com, hotels.com or lastminute.com",

    "- Latitude and longitude of the hotel (for map display)",

    "- WHY cyclists choose this hotel specifically: mention bike storage, route access, bike wash, early breakfast, proximity to key roads, any cycling packages",

    "Also find 2 bike shops per destination with name, address, lat/lng, and services.",

    "",

    "Return ONLY valid JSON:",

    '{"destinations":[{"name":"<dest>","stayZone":"<area>","lat":<number>,"lng":<number>,"hotels":[{"name":"<name>","stars":"<e.g. 4-star>","source":"<Booking.com|Hotels.com|LastMinute.com>","rating":"<e.g. 8.6/10>","reviewCount":"<e.g. 2,341 reviews>","price":"<e.g. from EUR 89/night>","whyCyclists":"<cycling reasons>","url":"<booking url>","lat":<number>,"lng":<number>}],"bikeShops":[{"name":"<shop>","address":"<full address>","services":"<rental/repair/fitting>","lat":<number>,"lng":<number>}]}]}',

    "",

    "Be thorough. Return exactly 3 hotels and 2 bike shops per destination.",

  ].join("\n");

}











