// ── Generate smart packing list based on destination + user answers ────────

// Detect if trip involves significant timezone shift (jetlag warning)

const CONTINENT_TZ = {

  'Europe': 0, 'Africa': 2, 'Middle East': 3,

  'Asia': 7, 'Oceania': 10,

  'North America': -6, 'South America': -4,

};

const ORIGIN_TZ = (from_city='') => {

  const f = from_city.toLowerCase();

  if(['london','dublin','lisbon','reykjavik'].some(c=>f.includes(c))) return 0;

  if(['paris','berlin','rome','madrid','amsterdam','brussels'].some(c=>f.includes(c))) return 1;

  if(['sydney','melbourne','brisbane','auckland'].some(c=>f.includes(c))) return 10;

  if(['new york','boston','toronto','montreal'].some(c=>f.includes(c))) return -5;

  if(['chicago','dallas','houston','winnipeg'].some(c=>f.includes(c))) return -6;

  if(['denver','calgary'].some(c=>f.includes(c))) return -7;

  if(['los angeles','san francisco','vancouver','seattle'].some(c=>f.includes(c))) return -8;

  if(['tokyo','osaka','seoul'].some(c=>f.includes(c))) return 9;

  if(['bangkok','singapore','kuala lumpur'].some(c=>f.includes(c))) return 7;

  if(['dubai','abu dhabi'].some(c=>f.includes(c))) return 4;

  return null;

};

function getJetlagWarning(destContinent, fromCity) {

  const destTz = CONTINENT_TZ[destContinent];

  const originTz = ORIGIN_TZ(fromCity);

  if(destTz==null||originTz==null) return null;

  const diff = Math.abs(destTz - originTz);

  if(diff < 4) return null;

  const days = diff >= 8 ? 2 : 1;

  return { hours: diff, recoveryDays: days,

    msg: `~${diff}h time difference. Allow ${days} easy day${days>1?"s":""} before hard riding.`

  };

}



