function getDestCoords(destName) {

  // Approximate coords for cycling destination regions

  const DEST_APPROX = {

    'Girona':[41.98,2.82],'Mallorca North':[39.87,3.0],'Mallorca South':[39.5,2.9],

    'Calpe':[38.65,0.05],'Tenerife':[28.3,-16.6],'Lanzarote':[29.0,-13.6],

    'Gran Canaria':[27.9,-15.4],'Nice':[43.7,7.3],'Algarve':[37.1,-8.2],

    'Pyrenees':[42.8,1.6],'Dolomites':[46.5,11.9],'Tuscany':[43.4,11.1],

    'Andalusia':[37.2,-4.5],'Alentejo':[38.4,-7.9],'Douro Valley':[41.2,-7.6],

    'Normandy':[49.3,0.6],'Brittany':[48.2,-3.0],'Loire Valley':[47.5,0.7],

    'Bordeaux':[44.8,-0.6],'Alsace':[48.1,7.4],'Champagne':[49.3,3.9],

    'Corsica North':[42.7,9.0],'Corsica South':[41.6,8.8],'Sardinia':[40.1,9.0],

    'Sicily East':[37.1,15.1],'Lake Como':[46.0,9.1],'Lake Garda':[45.7,10.7],

    'Tuscany':[43.4,11.1],'Umbria':[43.1,12.4],'Puglia':[40.6,17.5],

    'Lisbon Coast':[38.7,-9.4],'Madeira':[32.7,-17.0],'Azores':[37.7,-25.7],

    'Yorkshire':[54.0,-1.5],'Lake District':[54.5,-3.1],'Scottish Highlands':[57.0,-4.5],

    'Mallorca':[39.7,3.0],'Ibiza':[39.0,1.4],'Menorca':[40.0,4.0],

    'Girona Coast':[41.9,3.0],'Valencia Inland':[39.5,-0.5],'Madrid Sierra':[40.7,-4.0],

    'Lanzarote':[29.0,-13.6],'Costa Brava':[42.2,2.8],'Algarve':[37.1,-8.2],

  };

  if(DEST_APPROX[destName]) return DEST_APPROX[destName];

  // Fall back to continent centre

  const meta = LOCATION_META[destName]||{};

  const centres = {'Europe':[48,10],'Africa':[0,20],'Asia':[35,80],'North America':[45,-95],'South America':[-15,-60],'Oceania':[-25,135],'Middle East':[27,43]};

  return centres[meta.continent||'Europe']||[48,10];

}



function getFlightTime(fromCity, destName) {

  const from = (fromCity||'').toLowerCase().trim();

  // Find best match in ORIGIN_COORDS

  let fromCoords = null;

  for(const [key,coords] of Object.entries(ORIGIN_COORDS)){

    if(from.includes(key)||key.includes(from.split(' ')[0])){fromCoords=coords;break;}

  }

  if(!fromCoords) return null;



  const toCoords = getDestCoords(destName);

  // Haversine distance

  const R=6371, dLat=(toCoords[0]-fromCoords[0])*Math.PI/180, dLon=(toCoords[1]-fromCoords[1])*Math.PI/180;

  const a=Math.sin(dLat/2)**2+Math.cos(fromCoords[0]*Math.PI/180)*Math.cos(toCoords[0]*Math.PI/180)*Math.sin(dLon/2)**2;

  const distKm = R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));



  // Estimate: avg 850 km/h cruise + 30min taxi/climb + 25min descent, under 500km add 20min extra

  const airHours = distKm/850;

  const groundMins = distKm < 500 ? 55 : 45;

  const totalMins = Math.round(airHours*60 + groundMins);



  if(totalMins < 50) return null; // probably same country, don't show

  if(totalMins < 90) return `~${totalMins}min flight`;

  const h = Math.floor(totalMins/60);

  const m = Math.round((totalMins%60)/15)*15;

  return m===0?`~${h}h flight`:m===60?`~${h+1}h flight`:`~${h}h${m}m flight`;

}



function getDestIntel(destName) {

  if(DEST_INTEL[destName]) return DEST_INTEL[destName];

  const meta = LOCATION_META[destName]||{};

  if(!meta.country) return null;

  // Auto-generate from metadata

  return {

    weather:{months:meta.months||"check locally",avgTemp:"varies",rain:"Check local forecast",wind:"Check locally",sunriseRide:"Start early in summer heat"},

    airport:{primary:`Nearest major airport to ${meta.baseTown||destName}`,secondary:"Check Google Flights for options",bikeNote:"Most airlines accept bike boxes (often as oversized baggage). Book ahead in peak season."},

    packingExtras:[],

    food:{preRide:"Ask hotel staff for local restaurant recommendations.",midRide:"Carry food for routes >3h if cafe locations are unknown.",postRide:"Local restaurants near your stay zone.",localFuel:"Local bakeries and cafes typically open 7-8am for cyclists."},

    localKnowledge:`${destName} is in ${meta.region||meta.country}. Base town: ${meta.baseTown||"see stay zone"}. Stay zone: ${meta.stayZone||"city centre"}. Bike hire: ${meta.bikeAnchor||"ask hotel to recommend local shops"}.`,

    warnings:`Always check road conditions before riding in ${meta.country}. Carry emergency contact numbers and a physical map. Ensure your travel insurance covers cycling.`

  };

}



// ── Helper: get stored route data for a destination ──────────────────────

function getPackingList(destName, ans) {

  const intel = getDestIntel(destName);

  const terrain = (ans.terrain||"").toLowerCase();

  const month = (ans.month||"").toLowerCase();

  const days = parseInt(ans.days)||4;

  const base = [

    "Helmet","Cycling shoes","Gloves (fingerless)","Sunglasses","Bib shorts x"+(Math.ceil(days/2)),"Cycling jersey x"+(Math.ceil(days/2)),"Base layer x2","Socks x"+(days+1),"Cycling cap","Garmin/Wahoo + charger","Phone mount","CO2 cartridges x4 or mini pump","Inner tubes x2","Tyre levers","Multi-tool","Chain lube (wet+dry)","Chamois cream","Sunscreen SPF50+","First aid kit (small)","Cash in local currency","Passport/ID",

  ];

  const extras = intel?.packingExtras||[];

  const terrainExtras = terrain.includes("gravel")||terrain.includes("mountain")?["Knee pads (optional)","Extra food for remote sections","GPS backup battery"]:[];

  const monthExtras = ["jan","feb","mar","nov","dec"].some(m=>month.includes(m))?["Thermal base layer","Leg warmers","Full-length gloves","Rain jacket","Overshoes"]:(["jul","aug"].some(m=>month.includes(m))?["Extra sunscreen","Electrolyte tabs","Ice socks (for summit descents)"]:[]);

  return [...new Set([...base,...extras,...terrainExtras,...monthExtras])];

}



// Get DEST_INTEL for any destination — stored data or auto-generated from LOCATION_META

function getStoredRoutes(destName) {

  for(const [key, val] of Object.entries(ROUTE_LINKS)) {

    if(destName && destName.toLowerCase().includes(key.toLowerCase())) return val;

  }

  return null;

}



// ── Check if destination has full stored data (no AI needed) ─────────────

function isFullyCurated(destName) {

  return !!(CURATED_HOTELS[destName] && getStoredRoutes(destName));

}







// ── Leaflet map component ────────────────────────────────────────────────

function LeafletMap({destName, destLat, destLng, hotels=[], bikeShops=[], routes=[], onSetBase}) {

  const mapRef = useRef(null);

  const [mapTab, setMapTab] = React.useState('hotels');

  const mapInstanceRef = useRef(null);

  const [baseInfo, setBaseInfo] = React.useState(null);

  const baseLayersRef = useRef([]);



  useEffect(()=>{

    if(!mapRef.current) return;

    if(mapInstanceRef.current){ mapInstanceRef.current.remove(); mapInstanceRef.current=null; }

    const lat = destLat||41.98, lng = destLng||2.82;

    if(!window.L){

      const lnk=document.createElement("link");lnk.rel="stylesheet";lnk.href="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";document.head.appendChild(lnk);

      const s=document.createElement("script");s.src="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";s.async=true;s.defer=true;s.onload=()=>initMap(lat,lng);document.head.appendChild(s);

    } else { initMap(lat,lng); }



    function haversineKm(lat1,lng1,lat2,lng2){

      const R=6371,dLat=(lat2-lat1)*Math.PI/180,dLon=(lng2-lng1)*Math.PI/180;

      const a=Math.sin(dLat/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;

      return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));

    }



    function setBase(bLat, bLng, bName){

      const L=window.L, map=mapInstanceRef.current; if(!map) return;

      baseLayersRef.current.forEach(l=>{ try{map.removeLayer(l);}catch(e){} });

      baseLayersRef.current=[];

      const starIcon=L.divIcon({html:`<div style="background:#e8b84b;color:#0a0a08;border-radius:50%;width:30px;height:30px;display:flex;align-items:center;justify-content:center;font-size:15px;border:3px solid #fff;box-shadow:0 0 0 3px rgba(232,184,75,0.5),0 4px 14px rgba(0,0,0,0.6);">★</div>`,iconSize:[30,30],iconAnchor:[15,15],className:""});

      const m=L.marker([bLat,bLng],{icon:starIcon,zIndexOffset:2000}).addTo(map).bindPopup(`<strong>⭐ Your base</strong><br>${bName}`);

      const c1=L.circle([bLat,bLng],{radius:15000,color:"rgba(232,184,75,0.2)",fill:true,fillColor:"rgba(232,184,75,0.04)",fillOpacity:1,weight:1,dashArray:"5,7"}).addTo(map);

      const c2=L.circle([bLat,bLng],{radius:30000,color:"rgba(232,184,75,0.1)",fill:false,weight:1,dashArray:"5,7"}).addTo(map);

      baseLayersRef.current=[m,c1,c2];

      setBaseInfo({lat:bLat,lng:bLng,name:bName});

      if(onSetBase) onSetBase({lat:bLat,lng:bLng,name:bName});

    }



    function initMap(lat, lng){

      if(!mapRef.current) return;

      const L=window.L;

      const map=L.map(mapRef.current,{zoomControl:true,scrollWheelZoom:false}).setView([lat,lng],11);

      mapInstanceRef.current=map;

      L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{attribution:"OSM",maxZoom:18,className:"map-tiles"}).addTo(map);



      // Route START POINT markers (no polylines — just mark where each route begins)

      const routeColors=["#e8b84b","#4aaa40","#4a9eff","#db7b7b","#9b7bdb"];

      const routeStarts=[]; // [{name, lat, lng, dist, elev, color}]

      routes.forEach((route,ri)=>{

        const wps=route.waypoints||[];

        if(wps.length>=1){

          const sp=wps[0];

          const color=routeColors[ri%routeColors.length];

          const routeIcon=L.divIcon({

            html:`<div style="background:${color};color:#0a0a08;border-radius:50%;width:22px;height:22px;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;border:2px solid #fff;box-shadow:0 2px 8px rgba(0,0,0,0.5);">${ri+1}</div>`,

            iconSize:[22,22],iconAnchor:[11,11],className:""

          });

          L.marker([sp.lat,sp.lng],{icon:routeIcon})

           .bindTooltip(`<b>Route ${ri+1}: ${route.name||""}</b>${route.dist?`<br/>${route.dist}`:""}${route.elev?` · ${route.elev} elev`:""}`,{sticky:true,className:"route-tooltip",direction:"top"})

           .addTo(map);

          routeStarts.push({name:route.name||`Route ${ri+1}`,lat:sp.lat,lng:sp.lng,dist:route.dist||"",elev:route.elev||"",color});

        }

      });



      // Hotel markers — show which routes are nearby

      window._setBaseFromMap=(bLat,bLng,bName)=>setBase(bLat,bLng,bName);

      const hIcon=L.divIcon({html:`<div style="background:#e8b84b;color:#000;border-radius:50%;width:24px;height:24px;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;border:2px solid #fff;box-shadow:0 2px 8px rgba(0,0,0,0.5);cursor:pointer;">H</div>`,iconSize:[24,24],iconAnchor:[12,12],className:""});

      hotels.forEach(h=>{

        if(h.lat&&h.lng){

          // Find which route starts are within 5km of this hotel

          const nearbyRoutes=routeStarts.filter(r=>haversineKm(h.lat,h.lng,r.lat,r.lng)<=5);

          const nearbyHtml=nearbyRoutes.length>0

            ? nearbyRoutes.map(r=>`<div style="display:flex;align-items:center;gap:6px;margin-top:4px;"><div style="background:${r.color};border-radius:50%;width:14px;height:14px;display:flex;align-items:center;justify-content:center;font-size:8px;font-weight:700;color:#0a0a08;flex-shrink:0;">${routeStarts.indexOf(r)+1}</div><span style="font-size:11px;color:#ccc;">${r.name}${r.dist?` · ${r.dist}`:""}</span></div>`).join("")

            : `<div style="font-size:11px;color:#666;margin-top:4px;">No marked route starts nearby</div>`;

          L.marker([h.lat,h.lng],{icon:hIcon}).addTo(map)

           .bindPopup(`<div style="min-width:170px;font-family:Georgia,serif">

              <div style="font-size:13px;font-weight:700;color:#f0ede8;margin-bottom:2px">${h.name}</div>

              <div style="font-size:11px;color:#aaa;margin-bottom:6px">${h.rating||""} ${h.stars||""}${h.price?` · ${h.price}`:""}</div>

              ${nearbyRoutes.length>0?`<div style="font-size:10px;color:#C9A96E;letter-spacing:1px;margin-bottom:2px;font-family:'DM Mono',monospace">ROUTES FROM HERE</div>${nearbyHtml}`:`<div style="font-size:10px;color:#666;font-family:'DM Mono',monospace">Routes via short transfer</div>`}

              <button onclick="window._setBaseFromMap(${h.lat},${h.lng},'${(h.name||"").replace(/'/g,"\\'")}');document.querySelectorAll('.leaflet-popup').forEach(p=>p.style.display='none');" style="width:100%;background:linear-gradient(180deg,#F0C654,#E8B84B);border:none;border-radius:6px;padding:7px 0;cursor:pointer;font-size:12px;font-weight:700;color:#0a0a08;margin-top:10px;">⭐ Set as my base</button>

            </div>`);

        }

      });



      // Bike shops

      const bIcon=L.divIcon({html:`<div style="background:#4aaa40;color:#fff;border-radius:4px;width:20px;height:20px;display:flex;align-items:center;justify-content:center;font-size:9px;font-weight:700;border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.4)">B</div>`,iconSize:[20,20],iconAnchor:[10,10],className:""});

      bikeShops.forEach(s=>{if(s.lat&&s.lng) L.marker([s.lat,s.lng],{icon:bIcon}).bindPopup(`<strong>${s.name}</strong><br><small>${s.services}</small>`).addTo(map);});



      // Click map to set custom base

      map.on("click",e=>setBase(e.latlng.lat,e.latlng.lng,"Custom location"));



      // Fit bounds to hotels + route starts

      const pts=[];

      hotels.forEach(h=>{if(h.lat&&h.lng)pts.push([h.lat,h.lng]);});

      routeStarts.forEach(r=>pts.push([r.lat,r.lng]));

      if(pts.length>1){try{map.fitBounds(pts,{padding:[24,24]});}catch(e){}}

      else if(pts.length===1){map.setView(pts[0],12);}

    }

    return ()=>{if(mapInstanceRef.current){mapInstanceRef.current.remove();mapInstanceRef.current=null;}};

  },[destLat,destLng,JSON.stringify(hotels),JSON.stringify(bikeShops),JSON.stringify(routes)]);



  return(

    <div style={{position:"relative"}}>

      <div style={{borderRadius:"8px",overflow:"hidden",border:"1px solid #1a1a18"}}>

        {/* Tab bar */}

        <div style={{display:"flex",background:"rgba(0,0,0,0.5)",borderBottom:"1px solid #1a1a18"}}>

          {[["hotels","🏨 Hotels"],["bikeshops","🚲 Bike shops"],["terrain","🗺 Terrain"]].map(([key,label])=>(

            <button key={key} onClick={()=>setMapTab&&setMapTab(key)}

              style={{flex:1,padding:"9px 0",background:mapTab===key?"rgba(232,184,75,0.12)":"transparent",

              border:"none",borderBottom:mapTab===key?"2px solid #E8B84B":"2px solid transparent",

              color:mapTab===key?"#E8B84B":"#555",fontFamily:"'DM Mono',monospace",fontSize:10,cursor:"pointer"}}>

              {label}

            </button>

          ))}

        </div>

        <iframe

          title="map"

          width="100%" height="280"

          style={{display:"block",border:"none"}}

          loading="lazy"

          allowFullScreen

          referrerPolicy="no-referrer-when-downgrade"

          src={

            mapTab==="bikeshops"

              ? `https://www.google.com/maps/embed/v1/search?key=${import.meta.env.VITE_GOOGLE_MAPS_KEY}&q=${encodeURIComponent("bike shop "+(selectedDest?.name||""))}&center=${lat||0},${lng||0}&zoom=13`

              : mapTab==="terrain"

              ? `https://www.google.com/maps/embed/v1/view?key=${import.meta.env.VITE_GOOGLE_MAPS_KEY}&center=${lat||0},${lng||0}&zoom=11&maptype=terrain`

              : `https://www.google.com/maps/embed/v1/search?key=${import.meta.env.VITE_GOOGLE_MAPS_KEY}&q=${encodeURIComponent("hotels "+(selectedDest?.name||""))}&center=${lat||0},${lng||0}&zoom=13`

          }

        />

        <div style={{display:"flex",justifyContent:"flex-end",padding:"8px 12px",background:"rgba(0,0,0,0.3)"}}>

          <a href={`https://www.google.com/maps/search/${encodeURIComponent(mapTab==="bikeshops"?"bike shop "+(selectedDest?.name||""):"hotels "+(selectedDest?.name||""))}`}

            target="_blank" rel="noopener noreferrer"

            style={{fontFamily:"'DM Mono',monospace",fontSize:10,color:"#E8B84B",textDecoration:"none"}}>

            Open in Google Maps →

          </a>

        </div>

      </div>

      

      {/* Top instruction / confirmation */}

      <div style={{position:"absolute",top:"10px",left:"50%",transform:"translateX(-50%)",zIndex:1000,pointerEvents:"none",whiteSpace:"nowrap"}}>

        {!baseInfo?(

          <div style={{background:"rgba(10,10,9,0.88)",backdropFilter:"blur(6px)",border:"1px solid rgba(232,184,75,0.2)",borderRadius:"20px",padding:"5px 14px"}}>

            <span style={{fontFamily:"'DM Mono','Courier New',monospace",fontSize:"10px",color:"#C9A96E"}}>Click H hotel (or map) to ⭐ set your base</span>

          </div>

        ):(

          <div style={{background:"rgba(45,155,131,0.15)",backdropFilter:"blur(6px)",border:"1px solid rgba(45,155,131,0.5)",borderRadius:"20px",padding:"5px 14px"}}>

            <span style={{fontFamily:"'DM Mono','Courier New',monospace",fontSize:"10px",color:"#2D9B83"}}>⭐ Base: {baseInfo.name.length>38?baseInfo.name.slice(0,38)+"…":baseInfo.name}</span>

          </div>

        )}

      </div>

      {/* Legend */}

      <div style={{position:"absolute",bottom:"8px",left:"8px",background:"rgba(10,10,9,0.85)",backdropFilter:"blur(4px)",border:"1px solid #2a2a28",borderRadius:"5px",padding:"5px 10px",display:"flex",gap:"10px",zIndex:1000,pointerEvents:"none"}}>

        <div style={{display:"flex",alignItems:"center",gap:"4px"}}><div style={{width:"16px",height:"16px",background:"#e8b84b",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"9px",color:"#000",fontWeight:"700"}}>H</div><span style={{fontFamily:"'DM Mono',monospace",fontSize:"9px",color:"#9a9a94"}}>Hotel</span></div>

        <div style={{display:"flex",alignItems:"center",gap:"4px"}}><div style={{width:"16px",height:"16px",background:"#e8b84b",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"9px",color:"#000",fontWeight:"700"}}>1</div><span style={{fontFamily:"'DM Mono',monospace",fontSize:"9px",color:"#9a9a94"}}>Route start</span></div>

        <div style={{display:"flex",alignItems:"center",gap:"4px"}}><span style={{fontSize:"11px"}}>⭐</span><span style={{fontFamily:"'DM Mono',monospace",fontSize:"9px",color:"#C9A96E"}}>Your base</span></div>

      </div>

    </div>

  );

}





