  const API = "https://cycylingplanner.rewardspy.workers.dev";



  async function apiCall(path, opts={}) {

    const headers = {'Content-Type':'application/json'};

    if(authToken) headers['Authorization'] = `Bearer ${authToken}`;

    const res = await fetch(API + path, {...opts, headers:{...headers,...(opts.headers||{})} });

    const data = await res.json();

    return {ok: res.ok, data, status: res.status};

  }



  useEffect(()=>{

    // Restore session from localStorage on mount

    if(authToken){

      apiCall('/api/auth/me').then(r=>{

        if(r.ok){ setAuthUser(r.data); loadUserProfile(); }

        else { localStorage.removeItem('ctp_token'); setAuthToken(''); }

      }).catch(()=>{});

    }

  }, []); // eslint-disable-line



  async function loadUserProfile(){

    const r = await apiCall('/api/profile');

    if(r.ok){

      setUserProfile(r.data.profile);

      setSavedDests(r.data.profile.savedDestinations||[]);

      if(r.data.profile.lastAnswers && !Object.keys(ans).length){

        setAns(prev=>({...r.data.profile.lastAnswers,...prev}));

      }

    }

  }



  async function doAuthSubmit(){

    setAuthError('');

    setAuthLoading(true);

    try{

      const path = authMode==='register' ? '/api/auth/register' : '/api/auth/login';

      const body = authMode==='register'

        ? {email:authForm.email.trim(),password:authForm.password,name:authForm.name.trim()}

        : {email:authForm.email.trim(),password:authForm.password};

      const r = await apiCall(path,{method:'POST',body:JSON.stringify(body)});

      if(!r.ok){ setAuthError(r.data.error||'Something went wrong'); setAuthLoading(false); return; }

      const {token, user} = r.data;

      localStorage.setItem('ctp_token', token);

      setAuthToken(token);

      setAuthUser(user);

      setShowAuthModal(false);

      setAuthForm({name:'',email:'',password:''});

      showToast(`Welcome${authMode==='register'?' aboard':' back'}, ${user.name.split(' ')[0]}!`);

      setTimeout(loadUserProfile, 200);

    } catch(e){

      setAuthError('Network error — check your connection');

    }

    setAuthLoading(false);

  }



  function doLogout(){

    localStorage.removeItem('ctp_token');

    setAuthToken('');

    setAuthUser(null);

    setUserProfile(null);

    setSavedDests([]);

    setShowProfilePanel(false);

    showToast('Signed out');

  }



  async function saveProfileToServer(answers, results){

    if(!authToken) return;

    try{

      await apiCall('/api/profile', {

        method: 'PUT',

        body: JSON.stringify({

          lastAnswers: answers,

          lastResults: results.slice(0,5).map(b=>({name:b.name,country:b.country,score:b.score})),

          savedDestinations: savedDests,

          homeCity: answers.from||'',

          units: useMetric?'metric':'imperial',

        })

      });

    } catch(e){}

  }



  async function toggleSaveDest(b){

    if(!authToken){ setShowAuthModal(true); setAuthMode('register'); return; }

    const already = savedDests.find(d=>d.name===b.name);

    if(already){

      const next = savedDests.filter(d=>d.name!==b.name);

      setSavedDests(next);

      showToast(`${b.name} removed from saved`);

      await apiCall('/api/profile',{method:'PUT',body:JSON.stringify({savedDestinations:next,homeCity:ans.from||'',units:useMetric?'metric':'imperial'})});

    } else {

      const r = await apiCall('/api/profile/save-dest',{method:'POST',body:JSON.stringify({dest:{name:b.name,country:b.country}})});

      if(r.ok){ setSavedDests(r.data.saved); showToast(`${b.name} saved to your profile ✓`); }

    }

  }





  // ── Calorie burn estimator ───────────────────────────────────────────────

  function estimateCalories(ability, hours, terrain) {

    const h = parseFloat(hours) || 4;

    // MET values per activity type & ability

    const MET = {

      road:     {beginner:6,casual:7,intermediate:9,strong:11,elite:13,ebike:4},

      gravel:   {beginner:5,casual:6,intermediate:8,strong:10,elite:12,ebike:4},

      mountain: {beginner:7,casual:8,intermediate:10,strong:12,elite:14,ebike:5},

      touring:  {beginner:5,casual:5,intermediate:6,strong:7,elite:8,ebike:3},

    };

    const weightKg = 75; // average rider

    const met = (MET[terrain]||MET.road)[ability]||8;

    const kcal = Math.round(met * weightKg * h);

    return {kcal, perHour: Math.round(met * weightKg)};

  }





