  const _imgCache = {};

  const getImg = (name) => {

    if(!name) return DEST_IMAGES.default;

    if(_imgCache[name]) return _imgCache[name];

    for(const [k,v] of Object.entries(DEST_IMAGES)){

      if(name.toLowerCase().includes(k.toLowerCase())){

        _imgCache[name]=v; return v;

      }

    }

    _imgCache[name]=DEST_IMAGES.default;

    return DEST_IMAGES.default;

  };



