  // Simple elevation SVG generator

  const ElevationChart = ({points=[]}) => {

    if(!points||points.length<2) return null;

    const max=Math.max(...points,1);

    const w=300,h=60;

    const pts=points.map((v,i)=>`${(i/(points.length-1))*w},${h-((v/max)*h*0.9+4)}`).join(" ");

    const area=`0,${h} ${pts} ${w},${h}`;

    return(

      <svg viewBox={`0 0 ${w} ${h}`} style={{width:"100%",height:"60px"}}>

        <defs>

          <linearGradient id="elvGrad" x1="0" y1="0" x2="0" y2="1">

            <stop offset="0%" stopColor="#e8b84b" stopOpacity="0.4"/>

            <stop offset="100%" stopColor="#e8b84b" stopOpacity="0.05"/>

          </linearGradient>

        </defs>

        <polygon points={area} fill="url(#elvGrad)"/>

        <polyline points={pts} fill="none" stroke="#e8b84b" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>

      </svg>

    );

  };



